#!/bin/bash
set -e
echo "🔧 Fix import route CSV parser..."
cd "$(git rev-parse --show-toplevel)"

python3 - << 'INNER'
import base64
encoded = ""
content = base64.b64decode(encoded).decode("utf-8")
with open("src/app/api/import/route.ts", "w") as f:
    f.write(content)
print("File written OK")
INNER

git add src/app/api/import/route.ts
git commit -m "fix: CSV parser regex properly escaped via base64 deploy"
git push
echo "Déployé !"
